function rntext($v){$v=iconv('UTF-8','Windows-1252//TRANSLIT//IGNORE',(string)$v);return str_replace(['\\','(',')'],['\\\\','\\(','\\)'],$v);}
$lines=['REKAPITULASI NILAI SISWA - SMK JAYA BUANA',$info['nama_mapel'].' | '.$info['nama_kelas'].' | '.$info['nama_guru'],'Semester '.$info['semester'].' | '.$info['tahun_ajaran'],str_repeat('-',115)];$heads=['No','NISN','Nama'];foreach($components as $c)$heads[]=$c['nama_komponen'].' '.$c['bobot'].'%';$heads[]='Akhir';$lines[]=implode(' | ',$heads);$lines[]=str_repeat('-',115);
foreach($students as $i=>$s){$parts=[$i+1,$s['nisn'],$s['nama_lengkap']];$final=0;foreach($components as $c){$autoMap=['Ulangan Harian'=>'nilai_ulangan','Tugas Harian'=>'nilai_tugas','Kehadiran'=>'nilai_kehadiran'];$v=isset($autoMap[$c['nama_komponen']])?(float)$s[$autoMap[$c['nama_komponen']]]:(float)($scores[$s['id']][$c['id']]??0);$parts[]=number_format($v,2);$final+=$v*$c['bobot']/100;}$parts[]=number_format($final,2);$text=implode(' | ',$parts);foreach(str_split($text,115) as $part)$lines[]=$part;}
$chunks=array_chunk($lines,48);$objs=[1=>'<< /Type /Catalog /Pages 2 0 R >>',3=>'<< /Type /Font /Subtype /Type1 /BaseFont /Courier >>'];$kids=[];$n=4;foreach($chunks as $chunk){$p=$n++;$c=$n++;$kids[]="$p 0 R";$cmd="BT /F1 8 Tf 30 560 Td 11 TL\n";foreach($chunk as $line)$cmd.='('.rntext($line).") Tj T*\n";$cmd.='ET';$objs[$p]="<< /Type /Page /Parent 2 0 R /MediaBox [0 0 842 595] /Resources << /Font << /F1 3 0 R >> >> /Contents $c 0 R >>";$objs[$c]="<< /Length ".strlen($cmd)." >>\nstream\n$cmd\nendstream";}$objs[2]='<< /Type /Pages /Kids ['.implode(' ',$kids).'] /Count '.count($kids).' >>';ksort($objs);$pdf="%PDF-1.4\n";$off=[0];foreach($objs as $i=>$o){$off[$i]=strlen($pdf);$pdf.="$i 0 obj\n$o\nendobj\n";}$xref=strlen($pdf);$max=max(array_keys($objs));$pdf.="xref\n0 ".($max+1)."\n0000000000 65535 f \n";for($i=1;$i<=$max;$i++)$pdf.=sprintf('%010d 00000 n ',$off[$i])."\n";$pdf.="trailer\n<< /Size ".($max+1)." /Root 1 0 R >>\nstartxref\n$xref\n%%EOF";header('Content-Type: application/pdf');header('Content-Disposition: attachment; filename="'.$filename.'.pdf"');header('Content-Length: '.strlen($pdf));echo$pdf;
